import React, { useRef, useMemo, useLayoutEffect } from 'react';
import { useFrame } from '@react-three/fiber';
import { InstancedMesh, Object3D, Color, MathUtils, Group } from 'three';

export const AsteroidBelt: React.FC<{ isPaused: boolean; simulationSpeed: number }> = ({ isPaused, simulationSpeed }) => {
  const meshRef = useRef<InstancedMesh>(null);
  const groupRef = useRef<Group>(null);
  // Increased count because the orbit is larger now, need more rocks to look dense
  const count = 750; 
  const dummy = useMemo(() => new Object3D(), []);

  // Generate random data for asteroids
  const particles = useMemo(() => {
    const temp = [];
    // CORRECTION: Main Asteroid Belt is between Mars (Distance 36) and Jupiter (Distance 52)
    const minRadius = 39; 
    const maxRadius = 48; 

    for (let i = 0; i < count; i++) {
      // Random radius within the belt
      const r = MathUtils.randFloat(minRadius, maxRadius);
      // Random angle
      const theta = MathUtils.randFloat(0, Math.PI * 2);

      // Convert polar to cartesian coordinates (flat disk)
      const x = r * Math.cos(theta);
      const z = -r * Math.sin(theta); // Counter-clockwise

      // Slight vertical spread
      const y = MathUtils.randFloatSpread(1.5);

      // Random scale for variety
      const scale = MathUtils.randFloat(0.1, 0.4);

      // Random rotation
      const rotation = [
        Math.random() * Math.PI,
        Math.random() * Math.PI,
        Math.random() * Math.PI
      ];

      temp.push({ x, y, z, scale, rotation });
    }
    return temp;
  }, []);

  // Set initial positions
  useLayoutEffect(() => {
    if (meshRef.current) {
      // BRIGHTER PALETTE: Silver, Light Grey, Pale Rock colors
      const color = new Color();
      const palette = ['#E5E7EB', '#D1D5DB', '#9CA3AF', '#C4B5FD'];

      particles.forEach((particle, i) => {
        const { x, y, z, scale, rotation } = particle;

        dummy.position.set(x, y, z);
        dummy.rotation.set(rotation[0], rotation[1], rotation[2]);
        dummy.scale.set(scale, scale, scale);
        dummy.updateMatrix();

        meshRef.current!.setMatrixAt(i, dummy.matrix);

        // Pick a random color
        color.set(palette[Math.floor(Math.random() * palette.length)]);
        // Add slight variation for realism
        color.offsetHSL(0, 0, Math.random() * 0.1); 

        // REDUCE BRIGHTNESS: Scale color by 0.7
        color.multiplyScalar(0.7);

        meshRef.current!.setColorAt(i, color);
      });
      meshRef.current.instanceMatrix.needsUpdate = true;
      if (meshRef.current.instanceColor) meshRef.current.instanceColor.needsUpdate = true;
    }
  }, [particles, dummy]);

  // Rotate the entire belt group slowly to simulate orbit
  useFrame((state, delta) => {
    if (groupRef.current && !isPaused) {
      // Asteroid belt moves slower than inner planets
      groupRef.current.rotation.y += delta * 0.01 * simulationSpeed;
    }
  });

  return (
    <group ref={groupRef}>
      <instancedMesh ref={meshRef} args={[undefined, undefined, count]}>
        {/* Dodecahedron looks like a low-poly rock */}
        <dodecahedronGeometry args={[0.5, 0]} />
        <meshStandardMaterial 
          roughness={0.7} 
          metalness={0.2}
          color="#ffffff"
          emissive="#222222" // Slight self-glow to ensure visibility
          emissiveIntensity={0.35} 
        />
      </instancedMesh>
    </group>
  );
};

import React, { useEffect, useRef, useState } from 'react';
import { FilesetResolver, HandLandmarker, HandLandmarkerResult } from '@mediapipe/tasks-vision';

interface GestureControllerProps {
  onControl: (dx: number, dy: number, gestureType: 'rotate' | 'zoom') => void;
  onClose: () => void;
  isARMode: boolean;
  toggleARMode: () => void;
}

export const GestureController: React.FC<GestureControllerProps> = ({ 
  onControl, 
  onClose,
  isARMode,
  toggleARMode
}) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [loading, setLoading] = useState(true);
  const [permissionError, setPermissionError] = useState(false);
  const landmarkerRef = useRef<HandLandmarker | null>(null);
  const requestRef = useRef<number>(0);

  // State for zoom logic
  const prevHandDistanceRef = useRef<number | null>(null);

  // UI State
  const [statusMessage, setStatusMessage] = useState<string>("启动魔法手势...");

  useEffect(() => {
    const init = async () => {
      try {
        const vision = await FilesetResolver.forVisionTasks(
          "https://cdn.jsdelivr.net/npm/@mediapipe/tasks-vision@0.10.8/wasm"
        );

        landmarkerRef.current = await HandLandmarker.createFromOptions(vision, {
          baseOptions: {
            modelAssetPath: `https://storage.googleapis.com/mediapipe-models/hand_landmarker/hand_landmarker/float16/1/hand_landmarker.task`,
            delegate: "GPU"
          },
          runningMode: "VIDEO",
          numHands: 2 // Enable 2 hands for zoom
        });

        startWebcam();
      } catch (error) {
        console.error("Error initializing MediaPipe:", error);
        setLoading(false);
        setStatusMessage("初始化失败");
      }
    };
    init();

    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
      if (videoRef.current && videoRef.current.srcObject) {
        const tracks = (videoRef.current.srcObject as MediaStream).getTracks();
        tracks.forEach(t => t.stop());
      }
    };
  }, []);

  const startWebcam = async () => {
    if (!videoRef.current) return;
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ 
        video: { 
          width: { ideal: 640 },
          height: { ideal: 480 },
          facingMode: "user" 
        } 
      });
      videoRef.current.srcObject = stream;
      videoRef.current.addEventListener('loadeddata', predictWebcam);
      setLoading(false);
      setStatusMessage("准备好了！");
    } catch (err) {
      console.error("Webcam error:", err);
      setPermissionError(true);
      setLoading(false);
      setStatusMessage("无法打开摄像头");
    }
  };

  const predictWebcam = () => {
    if (!landmarkerRef.current || !videoRef.current || !canvasRef.current) return;

    if (videoRef.current.videoWidth === 0 || videoRef.current.videoHeight === 0) {
        requestRef.current = requestAnimationFrame(predictWebcam);
        return;
    }

    const startTimeMs = performance.now();
    const result = landmarkerRef.current.detectForVideo(videoRef.current, startTimeMs);

    processGestures(result);
    draw(result);

    requestRef.current = requestAnimationFrame(predictWebcam);
  };

  const processGestures = (result: HandLandmarkerResult) => {
    const hands = result.landmarks;

    // 1. No Hands -> Stop everything
    if (!hands || hands.length === 0) {
      onControl(0, 0, 'rotate');
      prevHandDistanceRef.current = null;
      setStatusMessage("挥挥手开始控制");
      return;
    }

    // 2. Two Hands -> ZOOM MODE
    if (hands.length === 2) {
      // Calculate centroid of Hand 1 and Hand 2
      const h1 = hands[0][9]; // Middle finger MCP (approx center of hand)
      const h2 = hands[1][9];

      // Calculate distance between hands (0.0 to 1.0 approx)
      const dist = Math.hypot(h1.x - h2.x, h1.y - h2.y);

      if (prevHandDistanceRef.current !== null) {
        const delta = dist - prevHandDistanceRef.current;

        // Threshold to ignore tiny jitters
        if (Math.abs(delta) > 0.005) {
           // LOGIC: 
           // Hands getting closer (delta negative) -> Zoom In (dollyIn) -> We send NEGATIVE dy to OrbitController for Zoom In logic?
           // Actually, let's look at OrbitController logic in App.tsx:
           // "dy < 0 (Hand Up) -> dollyIn". 
           // So if hands get closer (dist decreases, delta < 0), we want dollyIn.
           // So we pass 'delta' directly as 'dy'.
           // However, user prompt: "Hands pull near -> Lens near (Zoom In)".
           // hands getting closer -> dist decreases -> delta is negative.
           // hands moving apart -> dist increases -> delta is positive.

           // We'll multiply by a sensitivity factor
           // Pass delta directly: Negative = Zoom In, Positive = Zoom Out.
           onControl(0, delta * 200, 'zoom'); 

           if (delta < 0) setStatusMessage("🔍 拉近镜头");
           else setStatusMessage("🔭 拉远镜头");
        } else {
           onControl(0, 0, 'zoom');
        }
      }

      prevHandDistanceRef.current = dist;
      return;
    }

    // 3. One Hand -> ROTATE MODE
    if (hands.length === 1) {
      prevHandDistanceRef.current = null; // Reset zoom state

      const hand = hands[0];
      const cursor = hand[9]; // Use knuckle as stable center

      // Map 0-1 coordinates to -1 to 1 centered
      // Camera is mirrored, so X needs inversion if we want "Hand Right moves Map Right"
      // Usually: Move Hand Right -> Map Rotates Left (Camera orbits right)
      // Let's make it direct: Hand Right -> Camera moves Right (Orbit Left)

      const x = 1.0 - cursor.x; // Mirror X
      const y = cursor.y;

      let dx = 0;
      let dy = 0;

      const DEADZONE = 0.2;
      const CENTER = 0.5;

      // Calculate offset from center
      if (Math.abs(x - CENTER) > DEADZONE) {
         dx = (x - CENTER) * 2.5; // Gain
      }
      if (Math.abs(y - CENTER) > DEADZONE) {
         dy = (y - CENTER) * 2.5;
      }

      if (dx !== 0 || dy !== 0) {
        onControl(dx, dy, 'rotate');
        setStatusMessage("👆 正在移动方向");
      } else {
        onControl(0, 0, 'rotate');
        setStatusMessage("✋ 暂停中 (手在中间)");
      }
    }
  };

  const draw = (result: HandLandmarkerResult) => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    ctx.clearRect(0, 0, canvas.width, canvas.height);

    // In AR Mode (Fullscreen), we don't draw the semi-transparent black bg
    // We only draw debug info if needed, or clear controls
    if (!isARMode) {
      ctx.fillStyle = 'rgba(0, 0, 0, 0.3)';
      ctx.fillRect(0, 0, canvas.width, canvas.height);
    }

    const w = canvas.width;
    const h = canvas.height;

    // Draw Guide Center Zone (Visual Anchor)
    ctx.strokeStyle = 'rgba(255, 255, 255, 0.3)';
    ctx.lineWidth = 2;
    ctx.setLineDash([5, 5]);
    ctx.strokeRect(w * 0.3, h * 0.3, w * 0.4, h * 0.4);
    ctx.setLineDash([]);

    // Draw Hands
    if (result.landmarks) {
      for (const landmarks of result.landmarks) {
        // Draw Connectors
        const connections = HandLandmarker.HAND_CONNECTIONS;
        ctx.strokeStyle = "#00ffff";
        ctx.lineWidth = 3;

        for (const conn of connections) {
          const start = landmarks[conn.start];
          const end = landmarks[conn.end];
          // Remember to mirror X for drawing to match user perception
          ctx.beginPath();
          ctx.moveTo((1 - start.x) * w, start.y * h);
          ctx.lineTo((1 - end.x) * w, end.y * h);
          ctx.stroke();
        }

        // Draw Joints
        ctx.fillStyle = "#ff00ff";
        for (const lm of landmarks) {
           ctx.beginPath();
           ctx.arc((1 - lm.x) * w, lm.y * h, 4, 0, 2 * Math.PI);
           ctx.fill();
        }
      }
    }
  };

  return (
    <>
      {/* 
         AR MODE VIDEO LAYER 
         When AR Mode is ON: This fills the entire screen BEHIND everything (z-index -10)
         When AR Mode is OFF: Hidden
      */}
      {isARMode && (
         <div className="fixed inset-0 z-[-10] bg-black">
            <video 
              ref={videoRef} 
              className="w-full h-full object-cover -scale-x-100" 
              autoPlay 
              playsInline 
              muted
            />
         </div>
      )}

      {/* 
         CONTROL WIDGET LAYER (Bottom Right) 
         Displays the preview (mini) if not in AR mode, 
         and always displays controls/status.
      */}
      <div className="absolute bottom-4 right-4 z-50 flex flex-col items-end gap-3 pointer-events-auto animate-fade-in">

        {/* Status Bubble */}
        <div className="bg-slate-900/80 backdrop-blur border border-cyan-500/30 text-cyan-300 px-4 py-2 rounded-full font-bold shadow-lg flex items-center gap-2">
           <span className={`w-2 h-2 rounded-full ${loading ? 'bg-yellow-400' : 'bg-green-400'} animate-pulse`}></span>
           {statusMessage}
        </div>

        {/* Mini Preview (Only show if NOT in AR mode) */}
        {!isARMode && !loading && !permissionError && (
          <div className="relative rounded-xl overflow-hidden border-2 border-white/20 shadow-xl bg-black/50 w-[200px] h-[150px]">
             {/* We reuse the same video ref source, but since video element is moved in DOM when AR mode changes, 
                 we need to be careful. 
                 Actually, simpler approach: The video element is ALWAYS the source logic. 
                 If AR Mode is OFF, we render the video inside this box.
                 If AR Mode is ON, we render it fullscreen.
                 Wait, we can't easily move the Ref DOM node without React remounting it and losing stream.

                 BETTER APPROACH:
                 Video element is ALWAYS fixed hidden or fullscreen.
                 Canvas draws the debug view here.
             */}
             {!isARMode && (
                <video 
                  ref={videoRef} // React handles moving this DOM node seamlessly usually
                  className="w-full h-full object-cover -scale-x-100 opacity-50" 
                  autoPlay 
                  playsInline 
                  muted
                />
             )}
             <canvas 
               ref={canvasRef} 
               width={200}
               height={150}
               className="absolute top-0 left-0 w-full h-full"
             />
          </div>
        )}

        {/* Canvas for AR Mode (Invisible but needed for logic if we want) 
            Actually we can share the canvas ref, but scaling is different. 
            For simplicity in AR mode, we might skip drawing debug lines on screen 
            or draw them on a full screen canvas.
            Let's keep the mini-canvas logic simple: It handles the processing.
            When in AR mode, the video is Fullscreen, the mini-canvas is hidden visually 
            but we still need it for processing if possible, or just use the video stream data.
            MediaPipe uses the video element. The Canvas is just for USER FEEDBACK.
        */}

        <div className="flex items-center gap-3">
           {/* AR Toggle Button */}
           <button 
             onClick={toggleARMode}
             className={`h-12 px-5 rounded-full font-bold text-sm shadow-lg border-2 transition-all flex items-center gap-2
               ${isARMode 
                 ? 'bg-cyan-500 text-black border-cyan-200 shadow-[0_0_15px_#22d3ee]' 
                 : 'bg-slate-800 text-white border-slate-600 hover:bg-slate-700'
               }`}
           >
             <span>{isARMode ? "📺 关闭画面" : "📹 显示画面 (AR)"}</span>
           </button>

           {/* Close Button */}
           <button 
              onClick={onClose}
              className="w-12 h-12 bg-red-500 hover:bg-red-400 text-white rounded-full flex items-center justify-center shadow-lg border-2 border-white/20 active:scale-95 transition-all"
           >
              ✕
           </button>
        </div>
      </div>
    </>
  );
};

import React, { useState, Suspense, useRef, useMemo, useEffect } from 'react';
import { Canvas, useFrame } from '@react-three/fiber';
import { OrbitControls, Sparkles, PerspectiveCamera, Environment, Stars } from '@react-three/drei';
import { Vector3, TextureLoader, BackSide, Mesh, Object3D, RepeatWrapping, ClampToEdgeWrapping } from 'three';
import { PLANETS, SUN_DATA } from './constants';
import { Planet } from './components/Planet';
import { Sun } from './components/Sun';
import { Starship } from './components/Starship';
import { AsteroidBelt } from './components/AsteroidBelt';
import { UIOverlay } from './components/UIOverlay';
import { GestureController } from './components/GestureController';
import { generateStarFieldTexture } from './utils/textureGenerator';

const Skybox: React.FC = () => {
  const meshRef = useRef<Mesh>(null);
  const starTextureUrl = useMemo(() => generateStarFieldTexture(), []);
  const starTexture = useMemo(() => {
    const t = new TextureLoader().load(starTextureUrl);
    t.wrapS = RepeatWrapping;
    t.wrapT = ClampToEdgeWrapping; 
    return t;
  }, [starTextureUrl]);

  useFrame((state, delta) => {
    if (meshRef.current) {
      meshRef.current.rotation.y += delta * 0.0002; 
    }
  });

  return (
    <mesh ref={meshRef}>
      <sphereGeometry args={[500, 64, 64]} />
      <meshBasicMaterial 
        map={starTexture} 
        side={BackSide} 
        color="#ffffff"
      />
    </mesh>
  );
};

const OrbitController = ({ controlsRef, gestureVelocity }: { controlsRef: any, gestureVelocity: React.MutableRefObject<{dx: number, dy: number, gestureType: 'rotate' | 'zoom'}> }) => {
  useFrame(() => {
    if (controlsRef.current && controlsRef.current.enabled) {
      const { dx, dy, gestureType } = gestureVelocity.current;

      const threshold = 0.01;
      const isActive = Math.abs(dx) > threshold || Math.abs(dy) > threshold;

      if (isActive) {
          if (gestureType === 'rotate') {
             // ROTATE MODE
             // dx: Left/Right movement.
             // dy: Up/Down movement.

             // Smooth damping is handled by OrbitControls 'enableDamping', 
             // but we need to feed it small increments.

             controlsRef.current.setAzimuthalAngle(controlsRef.current.getAzimuthalAngle() - dx * 0.02);
             controlsRef.current.setPolarAngle(controlsRef.current.getPolarAngle() - dy * 0.02);
          } else if (gestureType === 'zoom') {
             // ZOOM MODE
             // dy contains the "Delta" of hand distance.
             // dy < 0: Hands getting closer (Pull Near) -> Zoom In (Dolly In)
             // dy > 0: Hands getting apart (Pull Far) -> Zoom Out (Dolly Out)

             const zoomSensitivity = 0.01;

             // We use a base scale of 1.0. 
             // Dolly In needs scale > 1.0 (e.g. 1.05)
             // Dolly Out needs scale < 1.0 (e.g. 0.95) OR use dollyOut helper.

             // Let's rely on direction.
             // Note: OrbitControls dollyIn(s) means "move camera closer by scale s". s > 1 means bigger step? 
             // Actually dollyIn(1.05) moves closer. dollyOut(1.05) moves further.

             const speed = 1.0 + Math.abs(dy * zoomSensitivity);

             if (dy < 0) {
                 // Negative delta = hands closer = Zoom In
                 controlsRef.current.dollyIn(speed);
             } else {
                 // Positive delta = hands apart = Zoom Out
                 controlsRef.current.dollyOut(speed);
             }
          }
          controlsRef.current.update();
      }
    }
  });
  return null;
}

const App: React.FC = () => {
  const [selectedPlanetId, setSelectedPlanetId] = useState<string | null>(null);
  const [isPaused, setIsPaused] = useState(false);
  const [simulationSpeed, setSimulationSpeed] = useState(1.0); 
  const [isStarshipActive, setIsStarshipActive] = useState(false);
  const [showPluto, setShowPluto] = useState(false);

  const [isGestureMode, setIsGestureMode] = useState(false);
  const [isARMode, setIsARMode] = useState(false); // AR Mode State

  const earthPositionRef = useRef<Vector3>(new Vector3(0, 0, 0));
  const planetRefs = useRef<{ [key: string]: Object3D }>({});
  const controlsRef = useRef<any>(null);

  const gestureVelocity = useRef<{dx: number, dy: number, gestureType: 'rotate' | 'zoom'}>({ dx: 0, dy: 0, gestureType: 'rotate' });

  const handleSelect = (id: string) => {
    setSelectedPlanetId(id);
    setIsPaused(true); 
  };

  const handleClose = () => {
    setSelectedPlanetId(null);
    setIsPaused(false); 
  };

  const togglePluto = () => {
    const newValue = !showPluto;
    setShowPluto(newValue);
    if (!newValue && selectedPlanetId === 'pluto') {
      handleClose();
    }
  };

  const handleGestureControl = (dx: number, dy: number, gestureType: 'rotate' | 'zoom') => {
    gestureVelocity.current = { dx, dy, gestureType };
  };

  const toggleGestureMode = () => {
    const nextState = !isGestureMode;
    setIsGestureMode(nextState);
    if (nextState) {
      setSimulationSpeed(1.0);
    } else {
      // If turning off gesture mode, also turn off AR
      setIsARMode(false);
    }
  };

  const handleToggleStarship = () => {
    const activating = !isStarshipActive;
    setIsStarshipActive(activating);
    if (activating) {
       setIsPaused(false);
       setSimulationSpeed(0.5); 
    } else {
       setSimulationSpeed(1.0);
    }
  };

  const handleMissionComplete = () => {
     setIsStarshipActive(false);
     setSimulationSpeed(1.0); 
  };

  const selectedPlanet = useMemo(() => {
    if (selectedPlanetId === 'sun') return SUN_DATA;
    return PLANETS.find(p => p.id === selectedPlanetId) || null;
  }, [selectedPlanetId]);

  const displayedPlanets = useMemo(() => {
    return showPluto ? PLANETS : PLANETS.filter(p => p.id !== 'pluto');
  }, [showPluto]);

  return (
    <div className="w-full h-screen relative overflow-hidden transition-colors duration-500"
         style={{ backgroundColor: isARMode ? 'transparent' : '#000' }}
    >

      <UIOverlay 
        selectedPlanet={selectedPlanet}
        onClose={handleClose}
        isPaused={isPaused}
        togglePause={() => setIsPaused(!isPaused)}
        simulationSpeed={simulationSpeed}
        setSimulationSpeed={setSimulationSpeed}
        isStarshipActive={isStarshipActive}
        toggleStarship={handleToggleStarship}
        showPluto={showPluto}
        togglePluto={togglePluto}
        isGestureMode={isGestureMode}
        toggleGestureMode={toggleGestureMode}
      />

      {isGestureMode && (
        <GestureController 
          onControl={handleGestureControl} 
          onClose={() => toggleGestureMode()} 
          isARMode={isARMode}
          toggleARMode={() => setIsARMode(!isARMode)}
        />
      )}

      {/* 
         Canvas needs alpha: true for transparency.
         When AR Mode is ON, we hide the Skybox and opaque layers so the video behind shows through.
      */}
      <Canvas gl={{ antialias: true, toneMappingExposure: 1.2, alpha: true }}>
        <Suspense fallback={null}>
          <PerspectiveCamera makeDefault position={[0, 80, 120]} fov={45} />

          <OrbitControls 
            ref={controlsRef}
            makeDefault
            enabled={!isStarshipActive} 
            enableDamping={true}
            dampingFactor={0.05}
            enablePan={false}
            minDistance={20}
            maxDistance={300}
            maxPolarAngle={Math.PI / 1.8}
            autoRotate={!selectedPlanetId && !isPaused && !isGestureMode && !isStarshipActive}
            autoRotateSpeed={0.15 * simulationSpeed}
          />

          <OrbitController controlsRef={controlsRef} gestureVelocity={gestureVelocity} />

          <Environment preset="city" environmentIntensity={0.3} />
          <pointLight position={[0, 0, 0]} intensity={2.5} distance={500} decay={1} color="#FFF5E0" />
          <ambientLight intensity={0.15} color="#404060" />

          {/* 1. Volumetric 3D Stars (Always show, they look nice floating in room) */}
          <Stars radius={400} depth={50} count={3000} factor={4} saturation={0.5} fade speed={0.5} />

          {/* 2. Painted Background (Skybox) - HIDE IN AR MODE */}
          {!isARMode && <Skybox />}

          {/* 3. Magical Dust */}
          <Sparkles count={400} scale={200} size={6} speed={0.2} opacity={0.4} noise={0.1} color="#88AAFF" />
          <Sparkles count={150} scale={150} size={3} speed={0.3} opacity={0.6} color="#FFD700" />

          <Sun 
             onSelect={handleSelect}
             isSelected={selectedPlanetId === 'sun'}
             isPaused={isPaused}
             simulationSpeed={simulationSpeed}
          />

          <AsteroidBelt isPaused={isPaused} simulationSpeed={simulationSpeed} />

          {displayedPlanets.map((planet) => (
            <Planet 
              key={planet.id} 
              data={planet} 
              isSelected={selectedPlanetId === planet.id}
              onSelect={handleSelect}
              isPaused={isPaused}
              simulationSpeed={simulationSpeed}
              earthPositionRef={earthPositionRef}
              planetRefs={planetRefs}
              isStarshipActive={isStarshipActive}
            />
          ))}

          {isStarshipActive && (
             <Starship 
                planetRefs={planetRefs} 
                onMissionComplete={handleMissionComplete}
             />
          )}

        </Suspense>
      </Canvas>
    </div>
  );
};

export default App;

import React from 'react';
import { PlanetData } from '../types';

interface UIOverlayProps {
  selectedPlanet: PlanetData | null;
  onClose: () => void;
  isPaused: boolean;
  togglePause: () => void;
  simulationSpeed: number;
  setSimulationSpeed: (speed: number) => void;
  isStarshipActive: boolean;
  toggleStarship: () => void;
  showPluto: boolean;
