// --- 中国空间站 (Tiangong Space Station) ---
const TiangongStation: React.FC<{ isPaused: boolean; simulationSpeed: number }> = ({ isPaused, simulationSpeed }) => {
  const stationRef = useRef<Group>(null);
  const solarPanelRef = useRef<Group>(null);

  useFrame((state, delta) => {
    if (stationRef.current && !isPaused) {
      // 空间站位于近地轨道，速度比月球快得多
      // Real physics: ISS/Tiangong orbits ~16x a day. Moon orbits ~1x a month.
      // Simulation: We make it spin fast enough to be noticeable and fun.
      stationRef.current.rotation.y += delta * 1.5 * simulationSpeed;
    }

    // 太阳翼缓慢调整角度（模拟对日定向）
    if (solarPanelRef.current && !isPaused) {
       solarPanelRef.current.rotation.x = Math.sin(state.clock.elapsedTime * 0.5) * 0.2;
    }
  });

  return (
    // 轨道倾角：天宫真实倾角约41度，这里视觉上稍微倾斜一点以区别于赤道
    <group rotation={[Math.PI / 6, 0, Math.PI / 4]}>
      <group ref={stationRef}>
        {/* 轨道半径：1.4 (地球表面是0.5, 月球在3.5) */}
        <group position={[1.4, 0, 0]} scale={[0.15, 0.15, 0.15]}> 

           {/* 悬浮标签 (Billboard ensures it always faces camera) */}
           <Billboard position={[0, 1.5, 0]}>
              <TextLabel text="🇨🇳 中国空间站" color="#ff4d4d" bgColor="rgba(255,255,255,0.9)" />
           </Billboard>

           {/* --- 空间站主体结构 (T字构型) --- */}

           {/* 1. 天和核心舱 (Core Module) - 垂直圆柱 */}
           <mesh rotation={[0, 0, Math.PI / 2]}>
              <cylinderGeometry args={[0.3, 0.3, 1.8, 16]} />
              <meshStandardMaterial color="#eeeeee" roughness={0.3} metalness={0.8} />
           </mesh>

           {/* 2. 问天/梦天实验舱 (Lab Modules) - T字横梁 */}
           <mesh position={[0, 0, 0]} rotation={[Math.PI / 2, 0, 0]}>
              <cylinderGeometry args={[0.25, 0.25, 1.2, 16]} />
              <meshStandardMaterial color="#e0e0e0" roughness={0.3} metalness={0.7} />
           </mesh>

           {/* 3. 对接口/节点舱 (Docking Hub) - 中间的小球 */}
           <mesh position={[0, 0, 0]}>
              <sphereGeometry args={[0.35, 16, 16]} />
              <meshStandardMaterial color="#ffffff" roughness={0.2} metalness={0.5} />
           </mesh>

           {/* --- 太阳翼系统 (Solar Wings) --- */}
           <group ref={solarPanelRef}>
             {/* 主太阳翼 (Large wings on the sides) */}
             <mesh position={[0, 0, 1.2]} rotation={[0.2, 0, 0]}>
                <boxGeometry args={[0.8, 0.05, 1.6]} />
                <meshStandardMaterial color="#1a237e" roughness={0.2} metalness={0.9} emissive="#0d47a1" emissiveIntensity={0.2} />
             </mesh>
             <mesh position={[0, 0, -1.2]} rotation={[-0.2, 0, 0]}>
                <boxGeometry args={[0.8, 0.05, 1.6]} />
                <meshStandardMaterial color="#1a237e" roughness={0.2} metalness={0.9} emissive="#0d47a1" emissiveIntensity={0.2} />
             </mesh>

             {/* 核心舱太阳翼 (Smaller wings on core) */}
             <mesh position={[0.8, 0, 0]} rotation={[0, 0, Math.PI / 2]}>
                <boxGeometry args={[0.4, 0.05, 1.0]} />
                <meshStandardMaterial color="#1a237e" roughness={0.2} metalness={0.9} />
             </mesh>
           </group>

           {/* 红旗点缀 (China Flag hint) */}
           <mesh position={[-0.5, 0.2, 0]} rotation={[0, 0, 0]}>
