             </mesh>

             {/* 3. 实验舱 I (Wentian) - Left Arm */}
             <mesh position={[-1.2, 0, -0.6]} rotation={[0, 0, Math.PI / 2]}>
                <cylinderGeometry args={[0.35, 0.4, 1.8, 16]} />
