export const generateChinaFlagTexture = (): string => {
  const width = 512;
  const height = 340; 
  let content = `<rect width="100%" height="100%" fill="#DE2910" />`;

  const drawStar = (cx: number, cy: number, r: number, rot: number) => {
      let points = "";
      for(let i=0; i<5; i++){
          const ang = (i * 72 - 90 + rot) * Math.PI / 180;
          points += `${cx + r * Math.cos(ang)},${cy + r * Math.sin(ang)} `;
          const ang2 = ((i * 72 + 36) - 90 + rot) * Math.PI / 180;
          points += `${cx + r*0.38 * Math.cos(ang2)},${cy + r*0.38 * Math.sin(ang2)} `;
      }
      return `<polygon points="${points}" fill="#FFDE00" />`;
  }

  content += drawStar(70, 70, 40, 0);
  content += drawStar(140, 40, 12, 20);
  content += drawStar(160, 65, 12, -10);
  content += drawStar(160, 95, 12, 0);
  content += drawStar(140, 120, 12, 15);

  return svgToBase64(content, width, height);
};

export const generateStarFieldTexture = (): string => {
    const width = 1024;
    const height = 512;
    let content = `<rect width="100%" height="100%" fill="#000000" />`;

    for(let i=0; i<400; i++) {
        const x = Math.random() * width;
        const y = Math.random() * height;
        const r = Math.random() * 1.5;
        const opacity = Math.random();
        content += `<circle cx="${x}" cy="${y}" r="${r}" fill="#FFFFFF" opacity="${opacity}" />`;
    }
    return svgToBase64(content, width, height);
};
